import{_ as e,o as l,c as i,a2 as t}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"可回看的 Agent 工作台","description":"","frontmatter":{"status":"Pattern Candidate","owner":"待指定","scope":"organization","last_reviewed":"2026-06-15T00:00:00.000Z"},"headers":[],"relativePath":"ai-native/patterns/observable-agent-workspace.md","filePath":"ai-native/patterns/observable-agent-workspace.md"}'),r={name:"ai-native/patterns/observable-agent-workspace.md"};function n(o,a,s,d,h,c){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="可回看的-agent-工作台" tabindex="-1">可回看的 Agent 工作台 <a class="header-anchor" href="#可回看的-agent-工作台" aria-label="Permalink to &quot;可回看的 Agent 工作台&quot;">​</a></h1><p><strong>状态：Pattern Candidate</strong></p><p><strong>Owner：待指定</strong></p><h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2><p>Agent 工作很快，但如果只留下最后结果，后来很难判断：</p><ul><li>当时为什么这么改？</li><li>哪一步是人批准的？</li><li>哪些检查真的跑过？</li><li>失败或中断发生在哪里？</li></ul><h2 id="模式" tabindex="-1">模式 <a class="header-anchor" href="#模式" aria-label="Permalink to &quot;模式&quot;">​</a></h2><p>把 Agent 工作台当成“可以回看的协作现场”，而不是一次性聊天窗口。</p><p>推荐做法：</p><ul><li>复杂任务先写计划，再执行。</li><li>关键动作留下检查点：开始、用工具前后、权限请求、子任务开始/结束、收尾。</li><li>人类审批和普通自动检查分开处理；审批可以等久一点，普通检查要快失败。</li><li>默认少外联，敏感信息只留在本地或密钥系统。</li><li>最终回答写清楚做了什么、怎么验证、还剩什么风险。</li></ul><h2 id="何时采用" tabindex="-1">何时采用 <a class="header-anchor" href="#何时采用" aria-label="Permalink to &quot;何时采用&quot;">​</a></h2><p>适合：</p><ul><li>多文件修改</li><li>跨仓协作</li><li>高权限工具</li><li>需要人类审批的任务</li><li>之后可能要复盘的工作</li></ul><h2 id="不适用" tabindex="-1">不适用 <a class="header-anchor" href="#不适用" aria-label="Permalink to &quot;不适用&quot;">​</a></h2><p>不适合把每个小动作都包装得很重。错别字、轻量链接修正、小范围 README 调整，可以直接改、直接验。</p><h2 id="代价与风险" tabindex="-1">代价与风险 <a class="header-anchor" href="#代价与风险" aria-label="Permalink to &quot;代价与风险&quot;">​</a></h2><ul><li>配置太重会打断节奏。</li><li>记录太细会让人不想看。</li><li>本地 hook、日志和计划不能泄露密钥、内部地址或私密上下文。</li></ul><h2 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h2><p>一次任务结束后，应该能快速回答：</p><ul><li>当时的计划是什么？</li><li>哪些动作需要人批准？</li><li>跑过哪些检查？</li><li>如果结果出问题，应从哪里回看？</li></ul><h2 id="采用证据" tabindex="-1">采用证据 <a class="header-anchor" href="#采用证据" aria-label="Permalink to &quot;采用证据&quot;">​</a></h2><ul><li>项目：Evolution Handbook</li><li>结果：本仓开始使用计划文件、<code>npm run check</code> 和 metadata 校验来保留可回看的工作轨迹。</li><li>限制：当前仍是 Pattern Candidate，尚未证明适用于所有项目。</li></ul>',22)])])}const b=e(r,[["render",n]]);export{u as __pageData,b as default};
